+        assert_eq!(batch.len(), 3);
+        assert_eq!(batch.texts(), vec!["text one", "text two", "text three"]);
+
+        batch.deliver(Ok(vec![vec![1.0], vec![2.0], vec![3.0]]));
+
+        assert_eq!(rx1.recv().unwrap().unwrap(), vec![1.0]);
