+                    sha256: PLACEHOLDER_VERIFY_AFTER_DOWNLOAD.to_owned(),
+                    size: 0,
+                },
+                ModelFile {
+                    name: "special_tokens_map.json".to_owned(),
+                    sha256: PLACEHOLDER_VERIFY_AFTER_DOWNLOAD.to_owned(),
