+fn invalid_state_transition(state: &ModelState, operation: &str, reason: &str) -> SearchError {
+    SearchError::InvalidConfig {
+        field: "model_state".to_owned(),
+        value: format!("{state:?}"),
+        reason: format!("invalid transition for {operation}: {reason}"),
+    }
+}
