+    let q = quantile.clamp(0.0, 1.0);
+    #[allow(clippy::cast_precision_loss)]
+    let adjusted = ((n as f64 + 1.0) * q).ceil();
+    #[allow(clippy::cast_precision_loss)]
+    let bounded = adjusted.max(1.0).min(n as f64);
+    bounded as usize - 1
+}
