+    // ─── Internal ─────────────────────────────────────────────────────
+
+    fn signal_weight(&self, signal: &FeedbackSignal) -> f64 {
+        match signal {
+            FeedbackSignal::Click { .. } => self.config.signal_weights.click,
+            FeedbackSignal::Dwell { duration_secs, .. } => {
