+
+        let selected = mmr_rerank(&scores, &refs, 4, &config);
+        // Pure relevance ordering: 0, 1, 2, 3
+        assert_eq!(selected, vec![0, 1, 2, 3]);
+    }
+
+    // ── Diversity effect ─────────────────────────────────────────────────
+
+    #[test]
