+        let norm: f32 = v.iter().map(|x| x * x).sum::<f32>().sqrt();
+        (norm - 1.0).abs() < 1e-5
+    }
+
+    // ── alpha=1.0 produces no expansion ──────────────────────────────────
+
+    #[test]
+    fn alpha_one_returns_original() {
