+        let result = prf_expand(&original, &feedback, 1.0).unwrap();
+
+        // alpha=1.0 means 100% original, 0% centroid.
+        // After L2 normalization, should be [1, 0, 0].
+        assert!(approx_eq(result[0], 1.0));
+        assert!(approx_eq(result[1], 0.0));
