+// ─── Helpers ────────────────────────────────────────────────────────────────
+
+/// Round `val` up to the next multiple of `align`.
+#[must_use]
+const fn align_up(val: usize, align: usize) -> usize {
+    (val + align - 1) & !(align - 1)
+}
