+    // ─── Dimension mismatch ─────────────────────────────────────────────
+
+    #[test]
+    fn dimension_mismatch_rejected() {
+        let path = temp_path("dim_mismatch.fsvi");
+        let mut writer =
+            VectorIndexWriter::create(&path, "test", "r1", 3, Quantization::F16).unwrap();
+
+        let result = writer.write_record("doc", &[1.0, 2.0]); // 2 != 3
+        assert!(result.is_err());
